var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 9월 30일 런던, <color=#ffd34c>황금 새벽회</color> 지하 사원\\n<color=#ffd34c>심야</color>","JPN":"1888年9月30日　ロンドン、<color=#ffd34c>黄金の暁団</color>地下寺院\\n<color=#ffd34c>深夜</color>","ENG":"[[","TWN":"1888年9月30日 倫敦, <color=#ffd34c>黃金黎明會</color> 地下寺廟\\n<color=#ffd34c>深夜</color>","SCN":"1888年9月30日 伦敦, <color=#ffd34c>黄金黎明会</color> 地下寺庙\\n<color=#ffd34c>深夜</color>","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"좋아, 지금이라면 괜찮겠지.","JPN":"よし、今なら大丈夫でしょう。","ENG":"Okay, it should be okay now.","TWN":"很好，這樣就差不多了吧。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"단지 교단에 입회하는 것만으로 그 비싼 마석을 아무렇지도 않게 넘기다니…….","JPN":"教団に入会しただけで、高額な魔石を渡してくれるなんて……","ENG":"I can't believe they're giving away those expensive Mana Stones for just joining the order...","TWN":"僅僅是加入教團，就能毫不費力地獲得昂貴的魔石……"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"황금 새벽회가 어떻게 마석을 만들어내는지는 모르겠지만.","JPN":"黄金の暁団がどうやって魔石を作っているのかはわからないけど。","ENG":"I'm not sure how the Golden Dawn is able to create Mana Stones, but.","TWN":"雖然不知道黃金黎明會是怎麼製造的。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이런 식이라면 마석이 필요한 이능력자를 잔뜩 끌어들일 수 있었을 거야.","JPN":"このやり方なら、魔石を求めている異能力者をたくさん入会させられるはず。","ENG":"They should be able to attract the Supernaturals as they need the Mana Stones.","TWN":"照這樣下去，肯定能吸引一大批需要魔石的超能力者。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"문제는 이곳의 신도 명단을 어떻게 얻어내느냐인데…….","JPN":"問題は、ここの信徒のリストをどうやって手に入れるかだけど……","ENG":"The issue at hand now is how I'm going to obtain the list of their members...","TWN":"問題是如何獲取名單……"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……잠깐.","JPN":"……待って。","ENG":"...Hold on.","TWN":"……等等。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"내가 뭘 이렇게까지 진지하게 생각하고 있는 거야?","JPN":"私、なんでこんなに真剣になっているの？","ENG":"Why am I thinking about this so seriously?","TWN":"我想這麼認真幹什麼呢？"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이건 그 남자의 일이잖아? 심야의 살인마 따위 내가 알게 뭐람?","JPN":"これはあの男の仕事よ？　深夜の殺人鬼なんか私の知ったことじゃない。","ENG":"This is his job, not mine. Why should I care about the Midnight Killer?","TWN":"這不是那個男人的事嗎？什麼午夜殺人魔，我才不管呢？"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"어차피 나는…….","JPN":"どうせ私は……","ENG":"Because I'm...","TWN":"反正我……"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다네. 비록 멀리서 바라볼 뿐이지만 항상 응원하고 있어.","JPN":"そのとおりだ。ただ遠くから見守っているだけだが、いつも応援している。","ENG":"Although I saw from afar, I'll always be cheering for you.","TWN":"是的。雖然只能遠遠地看著，但我一直在為你加油。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"팬이니까 말이야, 자네의.","JPN":"ファンだからな、君の。","ENG":"I'm actually a fan of yours.","TWN":"史旺，我是你的粉絲。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"무엇보다도 말이지.","JPN":"なにより。","ENG":"Above all else.","TWN":"最重要的是。"},"stage":{"bg":"LONDON_VICTORIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네와 내가 이렇게 만나게 된 것 자체가 그 훌륭한 반증이지 않은가?","JPN":"君と私がこうして出会えたこと自体、立派な反証ではないだろうか。","ENG":"Isn't the fact that you and I met like this an excellent rebuttal?","TWN":"你和我能這樣相遇，本身就是最好的證明，不是嗎？"},"stage":{"bg":"LONDON_VICTORIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 정답이야.","JPN":"ふふ、正解だ。","ENG":"Haha. That's correct.","TWN":"哈哈，答對了。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"역시 자네는 소질이 있군. 내 눈은 틀리지 않았어.","JPN":"やはり君には素質がある。私の目に狂いはなかったようだ。","ENG":"I knew you showed potential. My eyes are never wrong.","TWN":"果然你很有天賦。我的眼光沒有錯。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"으으! 무슨 엉뚱한 생각을 하고 있는 거야!","JPN":"うう…！　何考えてるの私！","ENG":"Errgh! Why am I thinking about him?","TWN":"呃呃！你在瞎想什麼呢！"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"정신차려, 스완! 어차피 그 능구렁이 같은 남자, 사진만 돌려받으면 볼 일도 없잖아?","JPN":"しっかりするのよ、スワン！　あの古狸みたいな男、写真さえ返してもらえたら用はない！","ENG":"Get a hold of yourself, Swan! You won't see that sly man ever again if you get that photo back, right?","TWN":"清醒點，史旺！只要把照片拿回來，就不用再見到那個狡猾的男人了，不是嗎？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그래, 내가 알아낸 걸 말하고, 사진을 돌려달라고 하자.","JPN":"そう、私が手に入れた情報を渡して、写真を返してもらおう。","ENG":"Okay. I'll tell him what I found out and get it back.","TWN":"好吧，這就回去告訴他我的發現，然後讓他把照片還給我。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이 정도 했으면, 사진 값은…….","JPN":"ここまでやったら写真の代価としては十分……","ENG":"I think I've done enough to get the photo back...","TWN":"做到這種程度，應該也抵得上那張照片的價值了……"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그나저나 여긴 어디지?","JPN":"というか、ここはどこ？","ENG":"Where am I?","TWN":"話說這裡是哪裡？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"안개가 너무 짙어서 방향을 잃어버리고 말았어.","JPN":"霧が濃すぎて、方向がわからなくなってしまった。","ENG":"The fog is too dense that I lost my sense of direction.","TWN":"霧太濃了，不知不覺迷失了方向。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};